import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

import DeanLayout from "../../layouts/DeanLayout";

import {
  getHodSubmissionById
} from "../../api/deanApi";

import hodQuestions from "../../data/hodQuestions";
function getAnswer(answers, questionNo) {

  const item = answers.find(
    (a) => String(a.questionNo) === String(questionNo)
  );

  return item ? item.answer : null;

}

function isImage(value) {

  if (!value) return false;

  return (
    value.endsWith(".jpg") ||
    value.endsWith(".jpeg") ||
    value.endsWith(".png") ||
    value.endsWith(".webp")
  );

}

function isFile(value) {

  if (!value) return false;

  return (
    value.endsWith(".pdf") ||
    value.endsWith(".doc") ||
    value.endsWith(".docx") ||
    value.endsWith(".xls") ||
    value.endsWith(".xlsx")
  );

}

function DeanHodView() {

  const { id } = useParams();

  const navigate = useNavigate();

  const [submission, setSubmission] =
    useState(null);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadSubmission();

  }, []);

  const loadSubmission = async () => {

    try {

      const res =
        await getHodSubmissionById(id);

      setSubmission(res.data.submission);

    }

    catch (err) {

      console.error(err);

    }

    finally {

      setLoading(false);

    }

  };

  if (loading) {

    return (

      <DeanLayout>

        <div style={{ padding: 40 }}>

          Loading...

        </div>

      </DeanLayout>

    );

  }

  if (!submission) {

    return (

      <DeanLayout>

        <div style={{ padding: 40 }}>

          Submission Not Found

        </div>

      </DeanLayout>

    );

  }

  return (

    <DeanLayout>

      <div
        style={{
          padding: "35px",
          maxWidth: "1400px",
          margin: "0 auto"
        }}
      >
                <button
          onClick={() => navigate(-1)}
          style={{
            position: "fixed",
            top: "90px",
            right: "30px",
            background: "#dc2626",
            color: "#fff",
            border: "none",
            padding: "12px 24px",
            borderRadius: "10px",
            cursor: "pointer",
            fontWeight: "600",
            zIndex: 9999
          }}
        >
          ✖ Close
        </button>

        <h1
          style={{
            marginBottom: "30px",
            color: "#1e293b"
          }}
        >
          HOD Submission Details
        </h1>

        <div
          style={{
            background: "#fff",
            borderRadius: "12px",
            padding: "25px",
            marginBottom: "35px",
            boxShadow: "0 2px 8px rgba(0,0,0,.08)"
          }}
        >

          <h2
            style={{
              color: "#2563eb",
              marginBottom: "20px"
